:root {
	/* ---------- Typography ---------- */
	--font-family: 'Plus Jakarta Sans', sans-serif;
	--font-weight-normal: 400;
	--font-weight-bold: 600;
	--font-size-body: 14px;
	--font-size-label: 14px;
	--font-size-test-notice: 12px;
	--font-size-input: 14px;
	--font-size-header: 28px;
	--font-size-paragraph: 14px;
	--font-size-link: 13px;
	--font-size-error: 12px;
	--font-size-html-h1: 32px;
	--font-size-html-h2: 24px;
	--font-size-html-h3: 18px;
	--font-size-html-h4: 16px;
	--font-size-html-h5: 14px;
	--font-size-html-h6: 12px;
	--font-size-subheader: 14px;

	/* ---------- Colors: The Void & The Pulse ---------- */
	--color-background: #000000;
	--color-test-notice-text: #4cd7f6;
	--color-test-notice-bg: rgba(76, 215, 246, 0.06);
	--color-test-notice-border: rgba(76, 215, 246, 0.25);
	--color-card-bg: rgba(19, 19, 19, 0.7);
	--color-card-border: rgba(61, 73, 76, 0.4);
	--color-card-shadow: rgba(76, 215, 246, 0.15);
	--color-link: #4cd7f6;
	--color-header: #ffffff;
	--color-label: #bcc9cd;
	--color-input-border: rgba(61, 73, 76, 0.5);
	--color-input-text: #ffffff;
	--color-focus-border: #4cd7f6;
	--color-submit-btn-bg: #4cd7f6;
	--color-submit-btn-text: #000000;
	--color-error: #ff4d6d;
	--color-required: #4cd7f6;
	--color-clear-button-bg: #3d494c;
	--color-html-text: #bcc9cd;
	--color-html-link: #4cd7f6;
	--color-header-subtext: #869397;

	/* ---------- Border Radii ---------- */
	--border-radius-card: 16px;
	--border-radius-input: 12px;
	--border-radius-clear-btn: 50%;
	--card-border-radius: 16px;

	/* ---------- Spacing (breathe in the void) ---------- */
	--padding-container-top: 40px;
	--padding-card: 40px;
	--padding-test-notice-vertical: 14px;
	--padding-test-notice-horizontal: 24px;
	--margin-bottom-card: 20px;
	--padding-form-input: 14px;
	--card-padding: 40px;
	--card-margin-bottom: 20px;

	/* ---------- Dimensions ---------- */
	--container-width: 520px;
	--submit-btn-height: 52px;
	--checkbox-size: 18px;

	/* ---------- Cyan Aura instead of shadow ---------- */
	--box-shadow-card: 0px 0px 40px 0px var(--color-card-shadow);
	--opacity-placeholder: 0.4;
}

/* ============================================================
   Celestial Nexus — Enhanced Effects
   ============================================================ */

/* Void background with subtle nebula */
body {
	background: #000000 !important;
	background-image:
		radial-gradient(circle at 15% 25%, rgba(76, 215, 246, 0.08) 0%, transparent 45%),
		radial-gradient(circle at 85% 75%, rgba(0, 91, 107, 0.12) 0%, transparent 50%) !important;
	background-attachment: fixed !important;
	color: #bcc9cd;
}

/* Glassmorphism for cards */
.card,
[class*="card"] {
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	background: rgba(19, 19, 19, 0.7) !important;
	border: 1px solid rgba(61, 73, 76, 0.4) !important;
}

/* Headlines — Space Grotesk with subtle glow */
h1, h2, h3, h4, h5, h6,
[class*="header"]:not([class*="subtext"]),
[class*="title"] {
	font-family: 'Space Grotesk', sans-serif !important;
	letter-spacing: -0.02em;
	text-shadow: 0 0 8px rgba(255, 255, 255, 0.15);
	color: #ffffff;
}

/* Labels */
label {
	color: #bcc9cd !important;
	letter-spacing: 0.01em;
}

/* Inputs — floating glass */
input,
textarea,
select {
	background: rgba(27, 27, 27, 0.6) !important;
	color: #ffffff !important;
	transition: all 0.25s ease;
	font-family: 'Plus Jakarta Sans', sans-serif;
}

input:focus,
textarea:focus,
select:focus {
	box-shadow: 0 0 0 4px rgba(76, 215, 246, 0.15) !important;
	border-color: #4cd7f6 !important;
	outline: none !important;
}

input::placeholder,
textarea::placeholder {
	color: #869397 !important;
	opacity: 0.6;
}

/* Submit Button — The Pulse gradient */
button[type="submit"],
[class*="submit"] {
	background: linear-gradient(135deg, #4cd7f6 0%, #005b6b 100%) !important;
	color: #ffffff !important;
	font-family: 'Space Grotesk', sans-serif !important;
	font-weight: 600 !important;
	letter-spacing: 0.02em;
	border: none !important;
	box-shadow: 0 0 20px rgba(76, 215, 246, 0.25);
	transition: all 0.25s ease;
	text-transform: uppercase;
	font-size: 14px !important;
}

button[type="submit"]:hover,
[class*="submit"]:hover {
	box-shadow: 0 0 32px rgba(76, 215, 246, 0.5) !important;
	transform: translateY(-1px);
}

/* Links — cyan with hover glow */
a {
	color: #4cd7f6 !important;
	text-decoration: none;
	transition: all 0.2s ease;
}

a:hover {
	opacity: 0.85;
	text-shadow: 0 0 8px rgba(76, 215, 246, 0.5);
}

/* Checkbox / Radio styling */
input[type="checkbox"],
input[type="radio"] {
	accent-color: #4cd7f6;
}

/* Scrollbar */
::-webkit-scrollbar {
	width: 8px;
	height: 8px;
}

::-webkit-scrollbar-track {
	background: #000000;
}

::-webkit-scrollbar-thumb {
	background: rgba(76, 215, 246, 0.3);
	border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
	background: rgba(76, 215, 246, 0.5);
}

/* Selection color */
::selection {
	background: rgba(76, 215, 246, 0.3);
	color: #ffffff;
}

/* Test notice — cyan alert style */
[class*="test-notice"] {
	backdrop-filter: blur(12px);
	-webkit-backdrop-filter: blur(12px);
}

