const item = $input.first();

const binaryKey = Object.keys(item.binary)[0];
const meta = item.binary[binaryKey];

const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);

const preparedBinary = await this.helpers.prepareBinaryData(
  buffer,
  meta.fileName,
  meta.mimeType
);

return [{
  json: {
    file_name: meta.fileName,
    file_length: meta.bytes,
    file_type: meta.mimeType
  },
  binary: {
    data: preparedBinary
  }
}];

