	color: #869397 !important;
	opacity: 0.6;
}

/* Submit Button — The Pulse gradient */
button[type="submit"],
[class*="submit"] {
	background: linear-gradient(135deg, #4cd7f6 0%, #005b6b 100%) !important;
	color: #ffffff !important;
	font-family: 'Space Grotesk', sans-serif !important;
	font-weight: 600 !important;
	letter-spacing: 0.02em;
	border: none !important;
	box-shadow: 0 0 20px rgba(76, 215, 246, 0.25);
	transition: all 0.25s ease;
	text-transform: uppercase;
	font-size: 14px !important;
}

button[type="submit"]:hover,
[class*="submit"]:hover {
	box-shadow: 0 0 32px rgba(76, 215, 246, 0.5) !important;
	transform: translateY(-1px);
}

/* Links — cyan with hover glow */
a {
	color: #4cd7f6 !important;
	text-decoration: none;
	transition: all 0.2s ease;
}

a:hover {
	opacity: 0.85;
	text-shadow: 0 0 8px rgba(76, 215, 246, 0.5);
}

/* Checkbox / Radio styling */
input[type="checkbox"],
input[type="radio"] {
	accent-color: #4cd7f6;
}

/* Scrollbar */
::-webkit-scrollbar {
	width: 8px;
	height: 8px;
}

::-webkit-scrollbar-track {
	background: #000000;
}

::-webkit-scrollbar-thumb {
	background: rgba(76, 215, 246, 0.3);
	border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
	background: rgba(76, 215, 246, 0.5);
}

/* Selection color */
::selection {
	background: rgba(76, 215, 246, 0.3);
	color: #ffffff;
}

/* Test notice — cyan alert style */
[class*="test-notice"] {
	backdrop-filter: blur(12px);
	-webkit-backdrop-filter: blur(12px);
}

