const form = $('Edit Profile Fields').item.json;
const handle = $input.first().json.h;

const body = { messaging_product: 'whatsapp' };

const aboutKey = Object.keys(form).find(k => k.startsWith('About'));
const descKey = Object.keys(form).find(k => k.startsWith('Description'));
const addrKey = Object.keys(form).find(k => k.startsWith('Address'));
const emailKey = Object.keys(form).find(k => k.startsWith('Email'));
const w1Key = Object.keys(form).find(k => k.startsWith('Website 1'));
const w2Key = Object.keys(form).find(k => k.startsWith('Website 2'));
const vertKey = Object.keys(form).find(k => k.startsWith('Industry'));

if (form[aboutKey]) body.about = form[aboutKey];
if (form[descKey]) body.description = form[descKey];
if (form[addrKey]) body.address = form[addrKey];
if (form[emailKey]) body.email = form[emailKey];

const websites = [];
if (form[w1Key]) websites.push(form[w1Key]);
if (form[w2Key]) websites.push(form[w2Key]);
if (websites.length) body.websites = websites;

if (form[vertKey]) body.vertical = form[vertKey];
if (handle) body.profile_picture_handle = handle;

return [{ json: { body } }];
